local M = {}

---@class Radar.Config
M.default = {
  keys = {
    prefix = "<space>",
    lock = "l",
    locks = { "1", "2", "3", "4", "5", "6", "7", "8", "9" },
    alternative = nil, -- defaults to prefix (double-tap to open alternative)
    recent = { "a", "s", "d", "f", "g" },
    vertical = "<C-v>",
    horizontal = "<C-s>",
    tab = "<C-t>",
    float = "<C-f>",
    line = {
      open = "<CR>",
      vertical = "V",
      horizontal = "S",
      tab = "T",
      float = "F",
    },
    tabs_toggle = "<leader>t",
  },

  persist = {
    path = vim.fs.joinpath(vim.fn.stdpath("data"), "radar", "data.json"),
    defer_ms = 500,
  },

  -- Window presets - users can override or add custom presets
  win_presets = {},

  -- Main radar window
  radar = {
    size = { width = 50, height = 75 },
    win_preset = "center",
    padding = { x = 2, y = 1 },
    border = "solid",
    position = "center",
    winblend = 0,
    max_recent_files = 10,
    show_empty_message = true,
    titles = {
      main = "󰐷  RADAR",
      locks = "󰋱  LOCKED IN",
      recent = "󰽏  NEAR",
    },
    win_opts = {
      number = false,
      relativenumber = false,
      cursorline = true,
      wrap = false,
    },
  },

  -- Lock label editor window
  radar_edit = {
    win_preset = "center",
    win_opts = {
      number = true,
      relativenumber = false,
      cursorline = true,
      wrap = false,
    },
  },

  -- File float window
  file_float = {
    win_preset = "center_narrow",
    win_opts = {
      number = true,
      relativenumber = true,
      cursorline = true,
      wrap = true,
    },
  },

  -- Tabs floating window
  tabs = {
    auto_close = true,
    win_preset = "center",
    win_opts = {
      number = false,
      cursorline = true,
      wrap = false,
    },
  },
}

return M

# Makefile for radar.nvim

.PHONY: test test-watch test-verbose lint typecheck selene check format install-hooks clean validate help

# Default target
help:
	@echo "Available targets:"
	@echo "  test          - Run all tests (using mini.test)"
	@echo "  test-watch    - Run tests in watch mode (requires entr)"
	@echo "  test-verbose  - Run tests with verbose output"
	@echo "  check         - Run all linters (lint + typecheck + selene)"
	@echo "  lint          - Check Lua formatting with stylua"
	@echo "  typecheck     - Run type checking (requires lua-language-server)"
	@echo "  selene        - Run selene linter (requires selene)"
	@echo "  format        - Format Lua files with stylua"
	@echo "  install-hooks - Enable pre-commit hooks (git config core.hooksPath .githooks)"
	@echo "  clean         - Clean test artifacts"
	@echo "  validate      - Validate test setup"
	@echo "  help          - Show this help message"

# Run all tests
test:
	@echo "Running radar.nvim tests..."
	nvim --headless -l test/run.lua

# Run tests with verbose output (same as regular for mini.test)
test-verbose:
	@echo "Running tests with verbose output..."
	nvim --headless -l test/run.lua

check:
	@echo "Running all checks..."
	@$(MAKE) --no-print-directory lint
	@$(MAKE) --no-print-directory typecheck
	@$(MAKE) --no-print-directory selene
	@echo ""

